package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithFirstRecordAsHeader() {
        CSVFormat baseFormat = CSVFormat.DEFAULT;
        CSVFormat resultFormat = baseFormat.withFirstRecordAsHeader();

        // It should be equal to calling withHeader() then withSkipHeaderRecord()
        CSVFormat expectedFormat = baseFormat.withHeader((String[]) null).withSkipHeaderRecord(true);

        assertNotNull(resultFormat, "Resulting CSVFormat should not be null");
        assertEquals(expectedFormat, resultFormat, "withFirstRecordAsHeader() should be equivalent to withHeader().withSkipHeaderRecord(true)");
        assertTrue(resultFormat.getSkipHeaderRecord(), "skipHeaderRecord should be true");
        assertNotNull(resultFormat.getHeader(), "Header should not be null");
    }
}
